const rows = $input.all().map(i => i.json);
const total = rows.reduce((s, r) => s + Number(r.total_cobrado || 0), 0);
const numCobros = rows.reduce((s, r) => s + Number(r.num_cobros || 0), 0);
const totales = rows.map(r => Number(r.total_cobrado || 0));
const mejor = totales.length ? Math.max(...totales) : 0;
const mejorRow = rows.find(r => Number(r.total_cobrado) === mejor);
const promedio = rows.length ? total / rows.length : 0;
return [{ json: {
  summary: { total_cobrado: total, num_cobros: numCobros, promedio_periodo: promedio, mejor_periodo: mejorRow?.periodo?.substring(0, 10) || '' },
  rows
} }];

const rows = $input.all().map(i => i.json);
const totalFact = rows.reduce((s, r) => s + Number(r.total_facturado || 0), 0);
const totalCobr = rows.reduce((s, r) => s + Number(r.total_cobrado || 0), 0);
const pendiente = rows.reduce((s, r) => s + Number(r.pendiente || 0), 0);
const pct = totalFact ? totalCobr / totalFact * 100 : 0;
return [{ json: {
  summary: { total_facturado: totalFact, total_cobrado: totalCobr, pendiente, pct_cobrado: pct },
  rows
} }];

const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  total_debt:     Number(r.total_debt     || 0),
  bucket_0_30:   Number(r.bucket_0_30   || 0),
  bucket_31_60:  Number(r.bucket_31_60  || 0),
  bucket_61_90:  Number(r.bucket_61_90  || 0),
  bucket_90_plus: Number(r.bucket_90_plus || 0),
}));
const totalDeuda  = rows.reduce((s, r) => s + r.total_debt,    0);
const bucket030   = rows.reduce((s, r) => s + r.bucket_0_30,   0);
const bucket3160  = rows.reduce((s, r) => s + r.bucket_31_60,  0);
const bucket6190  = rows.reduce((s, r) => s + r.bucket_61_90,  0);
const bucket90    = rows.reduce((s, r) => s + r.bucket_90_plus, 0);
return [{ json: {
  summary: { total_deuda: totalDeuda, num_deudores: rows.length, bucket_0_30: bucket030, bucket_31_60: bucket3160, bucket_61_90: bucket6190, bucket_90_plus: bucket90 },
  rows
} }];

const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  is_flow:          r.service_type === 'workflow',
  num_facturas:     Number(r.num_facturas     || 0),
  total_facturado:  Number(r.total_facturado  || 0),
  precio_promedio:  Number(r.precio_promedio  || 0),
  num_presupuestos: Number(r.num_presupuestos || 0),
  num_sesiones:     Number(r.num_sesiones     || 0),
  num_tratamientos: Number(r.num_tratamientos || 0),
}));
const total_facturado = rows.reduce((s, r) => s + r.total_facturado, 0);
const total_sesiones  = rows.reduce((s, r) => s + r.num_sesiones,    0);
const precio_promedio = rows.length ? rows.reduce((s, r) => s + r.precio_promedio, 0) / rows.length : 0;
const servicio_top    = rows[0]?.service_name || '';
const rowsWithPct = rows.map(r => ({
  ...r,
  pct_total: total_facturado ? r.total_facturado / total_facturado * 100 : 0,
}));
return [{ json: {
  summary: { total_servicios: rows.length, total_facturado, total_sesiones, precio_promedio, servicio_top },
  rows: rowsWithPct
} }];
